  ('social-worker-moex-01244', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法，私人或團體辦理兒童及少年福利機構，以向當地主管機關申 請設立許可者為限，其有對外勸募行為或享受租稅減免者，最遲應於設立許可之日起多久時間內 辦理財團法人登記？', '["1個月", "3個月", "6個月", "1年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
