  ('social-worker-moex-01248', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據家庭暴力防治法規定，下列何者並非屬於社會工作人員的職責？', '["被害人得於保護令審理時，聲請個案輔導之社工人員陪同在場", "裁定相對人對未成年子女會面交往之時間、地點及方式之前，得徵詢社工人員之意見", "執行保護令裁定內容，命相對人給付被害人住居所之租金或撫養費", "在執行職務時知有疑似家庭暴力情事者，應立即通報當地主管機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
