  ('social-worker-moex-01250', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據精神衛生法，下列關於精神醫療照護業務的敘述何者錯誤？', '["精神照護機構為保護病人安全，經告知病人後，得限制其活動之區域範圍", "精神醫療機構為醫療之目的或為防範緊急暴力意外，得拘束病人身體或限制其行動自由於特定 之保護設施內", "精神醫療機構於住院病人病情穩定或康復，無繼續住院治療之必要時，應通知本人或保護人辦 理出院，不得無故留置病人", "精神醫療機構診治病人或於病人住院時，僅應向其保護人說明病情及其應享有之權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
